+                SUM(api_input_tokens_total),
+                SUM(api_output_tokens_total),
+                SUM(api_cache_read_tokens_total),
+                SUM(api_cache_creation_tokens_total),
+                SUM(api_thinking_tokens_total)
+         FROM {table}
+         {where_clause}
+         GROUP BY {bucket_col}
+         ORDER BY {bucket_col}"
+    );
