+
+        let _ = app.update(CassMsg::AnalyticsEntered);
+        assert_eq!(app.surface, AppSurface::Analytics);
+        assert_eq!(app.view_stack, vec![AppSurface::Search]);
+    }
+
+    #[test]
+    fn analytics_entered_idempotent() {
+        let mut app = CassApp::default();
